import requests
import urllib.parse
from typing import Optional

def fetch_url_content(url: str, timeout: int = 30) -> Optional[str]:
    """
    Fetches and displays content from a URL with SSRF protection.
    
    Args:
        url (str): The URL to fetch content from
        timeout (int): Request timeout in seconds
        
    Returns:
        str: Content from the URL or None if failed
    """
    # Validate and sanitize URL
    try:
        parsed_url = urllib.parse.urlparse(url)
        if not parsed_url.scheme or not parsed_url.netloc:
            raise ValueError("Invalid URL format")
            
        # Prevent SSRF by checking for forbidden schemes
        if parsed_url.scheme not in ['http', 'https']:
            raise ValueError("Invalid URL scheme")
            
        # Additional SSRF protection: check for private IP ranges
        import ipaddress
        try:
            ip = ipaddress.ip_address(parsed_url.hostname)
            if ip.is_loopback or ip.is_private or ip.is_multicast:
                raise ValueError("Private IP address not allowed")
        except ValueError:
            # Not an IP address, continue with hostname validation
            pass
            
    except Exception as e:
        print(f"URL validation failed: {e}")
        return None
    
    try:
        response = requests.get(url, timeout=timeout)
        response.raise_for_status()
        return response.text
    except requests.exceptions.RequestException as e:
        print(f"Failed to fetch URL: {e}")
        return None

def process_webhook(url: str, headers: Optional[dict] = None) -> Optional[str]:
    """
    Process webhook from partner API with URL fetching capability.
    
    Args:
        url (str): The URL to fetch content from
        headers (dict): Optional headers for the request
        
    Returns:
        str: Content from the URL or None if failed
    """
    # Validate URL first
    if not url:
        return None
        
    # Add default headers if none provided
    if headers is None:
        headers = {
            'User-Agent': 'Partner-Integration-Client/1.0',
            'Accept': 'text/html,application/json'
        }
    
    # Fetch content with headers
    try:
        response = requests.get(url, headers=headers, timeout=30)
        response.raise_for_status()
        return response.text
    except requests.exceptions.RequestException as e:
        print(f"Webhook processing failed: {e}")
        return None